sql:
SELECT films.title, popularity.position
FROM films
INNER JOIN popularity ON films.film_id = popularity.film_id;

SELECT film_id, title, release_year
FROM films
WHERE runtime > 120;

SELECT film_id, SUM(views) AS total_views
FROM viewer_engagement
GROUP BY film_id;

external_knowledge:
- "Cinematic stars" metaphorically refers to films;
- "Night sky of popularity" is metaphorically used to describe the realm of film popularity;
- "Risen" refers to the increase in popularity;
- "Past lunar cycle" metaphorically refers to the last 30 days;
- "How brightly they shine on the IMDb scale" metaphorically refers to their IMDb rating.

sql:
SELECT COUNT(*) AS num_highly_rated_films
FROM films
WHERE imdb_rating >= 7.0;

SELECT f.title, f.production_company
FROM films f
JOIN marketing_campaigns m ON f.film_id = m.film_id;

external_knowledge:
- "cinematic stars" refers to films;
- "unique marks" refers to unique identifiers for each film;
- "shifted their identities" refers to films that underwent a title change;
- "blossomed in popularity" indicates an increase in the film's popularity;
- "cosmic year of 2020" is a metaphorical expression for the calendar year 2020.

- "rating change" refers to films that have had their rating altered;
- "marketing campaigns that took flight in the summer's last month of 2022" refers to marketing campaigns starting between August 1, 2022, and August 31, 2022;
- "average journey of their voyagers" includes measurements like views, watch time, likes, comments, and shares, which are indicators of audience engagement;
- "budget of their sails" refers to the financial resources allocated for marketing these films.

sql:
SELECT title
FROM films
WHERE runtime > (
    SELECT AVG(runtime) 
    FROM films
);

SELECT f.title, c.start_date, c.end_date, c.budget
FROM marketing_campaigns c
JOIN films f ON c.film_id = f.film_id;

SELECT title
FROM films
WHERE release_year = 2020 OR genre = 'action';
